#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> leaders(vector<int>& A) {
        int max_from_right = A.back();
        vector<int> leaders;
        leaders.push_back(max_from_right);
        for (int i = A.size() - 2; i >= 0; --i) {
            if (A[i] >= max_from_right) {
                max_from_right = A[i];
                leaders.push_back(max_from_right);
            }
        }
        reverse(leaders.begin(), leaders.end());
        return leaders;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> A(n);
    for (int i = 0; i < n; i++) cin >> A[i];
    Solution sol;
    vector<int> ans = sol.leaders(A);
    for (int leader : ans) {
        cout << leader << '\n';
    }
    return 0;
}
